import Link from "next/link";
import styles from "./navigation.module.css";

function Navigation() {
  return (
    <div className={styles.navigation}>
    <div className={styles.logo}>
          <Link href="/">
            <a>Home</a>
          </Link>
    </div>
      <ul className={styles.links}>
        <li>
          <Link href="/about">
            <a>About</a>
          </Link>
        </li>
        <li>
          <Link href="/blog/hello-world">
            <a>Blog</a>
          </Link>
        </li>
      </ul>
    </div>
  );
}

export default Navigation;
